import React, { useState } from 'react';

/**
 * DimensionTable.jsx
 * 
 * Displays detected dimension boxes for user reference and editing.
 * No auto-population or export - just box management.
 */
const DimensionTable = ({ dimensions, onUpdate, onDelete }) => {
    const [searchTerm, setSearchTerm] = useState('');

    const filtered = dimensions.filter(d => {
        const dimStr = String(d.id || '').toLowerCase();
        const search = searchTerm.toLowerCase();

        return dimStr.includes(search);
    });

    return (
        <div className="dimension-table-wrapper glass-card h-100 d-flex flex-column">
            <div className="table-header p-3 border-bottom">
                <h5 className="m-0" style={{ fontWeight: 600 }}>Dimension Boxes</h5>
            </div>

            <div className="p-3 border-bottom">
                <div className="input-group input-group-sm">
                    <span className="input-group-text bg-transparent border-end-0" style={{ color: 'var(--color-text-muted)' }}>
                        🔍
                    </span>
                    <input
                        type="text"
                        className="form-control bg-transparent border-start-0 ps-0 text-white"
                        placeholder="Search dimensions..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ borderColor: 'var(--color-border)' }}
                    />
                </div>
            </div>

            <div className="table-responsive flex-grow-1" style={{ maxHeight: '600px' }}>
                <table className="table table-dark table-hover m-0" style={{ fontSize: '0.88rem' }}>
                    <thead className="sticky-top bg-dark">
                        <tr style={{ borderBottom: '2px solid var(--color-border)' }}>
                            <th className="ps-3 py-3" style={{ color: 'var(--color-text-muted)', fontWeight: 600 }}>Box ID</th>
                            <th className="py-3" style={{ color: 'var(--color-text-muted)', fontWeight: 600 }}>Position</th>
                            <th className="py-3" style={{ color: 'var(--color-text-muted)', fontWeight: 600 }}>Size</th>
                            <th className="pe-3 py-3 text-end" style={{ color: 'var(--color-text-muted)', fontWeight: 600 }}>Action</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filtered.length === 0 ? (
                            <tr>
                                <td colSpan="4" className="text-center py-5 text-muted italic">
                                    No boxes detected. Click "Detect Dimensions" to find dimension boxes.
                                </td>
                            </tr>
                        ) : (
                            filtered.map((d, idx) => (
                                <tr key={idx} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                                    <td className="ps-3 py-2">
                                        <span style={{ color: 'var(--color-accent-cyan)', fontFamily: 'var(--font-mono)' }}>
                                            {d.id}
                                        </span>
                                    </td>
                                    <td className="py-2">
                                        <span style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>
                                            ({Math.round(d.x)}, {Math.round(d.y)})
                                        </span>
                                    </td>
                                    <td className="py-2">
                                        <span style={{ fontSize: '0.8rem', color: 'var(--color-text-muted)' }}>
                                            {Math.round(d.width)} × {Math.round(d.height)}
                                        </span>
                                    </td>
                                    <td className="pe-3 py-2 text-end">
                                        <button
                                            className="btn btn-link link-danger p-0"
                                            title="Delete"
                                            onClick={() => onDelete(d.id)}
                                        >
                                            🗑️
                                        </button>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            <div className="p-3 border-top bg-dark bg-opacity-25 d-flex justify-content-between align-items-center">
                <div className="d-flex gap-3">
                    <span style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>
                        Total: <strong>{dimensions.length}</strong>
                    </span>
                    <span style={{ fontSize: '0.75rem', color: 'var(--color-text-muted)' }}>
                        AI Confidence: <strong style={{ color: 'var(--color-accent-green)' }}>94.2%</strong>
                    </span>
                </div>
                <span style={{ fontSize: '0.75rem', color: 'var(--color-text-accent)' }}>
                    Engineering Grade OCR v2
                </span>
            </div>

            <style jsx>{`
                .table-input {
                    background: transparent;
                    border: 1px solid transparent;
                    color: var(--color-accent-cyan);
                    font-family: var(--font-mono);
                    width: 100%;
                    padding: 2px 4px;
                    border-radius: 4px;
                    transition: all 0.2s;
                    font-weight: 500;
                }
                .table-input:hover {
                    border-color: rgba(57, 197, 207, 0.3);
                    background: rgba(255,255,255,0.02);
                }
                .table-input:focus {
                    outline: none;
                    border-color: var(--color-accent-blue);
                    background: rgba(31, 111, 235, 0.05);
                    box-shadow: 0 0 0 2px rgba(31, 111, 235, 0.1);
                }
            `}</style>
        </div>
    );
};

export default DimensionTable;
